settings.custom_liquid:
{% assign today = 'now' | date: "%s" %}
{% assign morgen = today | plus: 86400 %}
{% assign tag = morgen | date: "%-d" %}
{% assign monat_nummer = morgen | date: "%-m" %}

{% case monat_nummer %}
  {% when '1' %}{% assign monat = 'Jan' %}
  {% when '2' %}{% assign monat = 'Feb' %}
  {% when '3' %}{% assign monat = 'März' %}
  {% when '4' %}{% assign monat = 'Apr' %}
  {% when '5' %}{% assign monat = 'Mai' %}
  {% when '6' %}{% assign monat = 'Juni' %}
  {% when '7' %}{% assign monat = 'Juli' %}
  {% when '8' %}{% assign monat = 'Aug' %}
  {% when '9' %}{% assign monat = 'Sep' %}
  {% when '10' %}{% assign monat = 'Okt' %}
  {% when '11' %}{% assign monat = 'Nov' %}
  {% when '12' %}{% assign monat = 'Dez' %}
{% endcase %}

<div style="text-align: left; margin-bottom: 24px;">
  <span style="color: #007000; font-size: 15px;">
    • Heute bestellt, Versand bis {{ tag }}. {{ monat }}
  </span>
</div>
